// Define an order type
interface Order {
  id: number;
  amount: number;
  isPaid: boolean;
}
const orders: Order[] = [
  { id: 1, amount: 25.0, isPaid: true },
  { id: 2, amount: 100.0, isPaid: false },
  { id: 3, amount: 75.0, isPaid: true },
];
// Filter: only paid orders
const paidOrders: Order[] = orders.filter(order => order.isPaid);
// Map: apply 8% tax to each amount
const withTax: number[] = paidOrders.map(order => order.amount * 1.08);
// Reduce: sum all amounts into a single total
const totalRevenue: number = withTax.reduce((sum, val) => sum + val, 0);
console.log('Paid orders with tax:', withTax);
console.log('Total revenue:', totalRevenue.toFixed(2));
// Expected: Paid orders with tax: [27, 81]
// Expected: Total revenue: 108.00
